const items = $input.all();

const gastos = items.filter(item => item.json.id != null);

if (gastos.length === 0) {
  return [{ json: { output: 'No se encontraron gastos registrados.' } }];
}

const lines = gastos.map((item, i) => {
  const fecha = new Date(item.json.fecha).toLocaleDateString('es-AR');
  const monto = parseFloat(item.json.monto).toFixed(2);
  return `${i + 1}. $${monto} — ${item.json.categoria} — ${item.json.descripcion} (${fecha})`;
});

const subtotales = {};
for (const item of gastos) {
  const cat = item.json.categoria;
  subtotales[cat] = (subtotales[cat] || 0) + parseFloat(item.json.monto);
}

const resumen = Object.entries(subtotales)
  .sort((a, b) => b[1] - a[1])
  .map(([cat, total]) => `  • ${cat}: $${total.toFixed(2)}`)
  .join('\n');

const output = `Últimos ${gastos.length} gastos:\n${lines.join('\n')}\n\nSubtotal por categoría:\n${resumen}`;

return [{ json: { output } }];
